import { client, SMSType } from '@/utils/type'
import CountDown from '@/components/public/countDown'
export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
       link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
    };
  },
  layout: "default_layout",
  components: {
    CountDown
  },
  async asyncData({$get}) {
    let registerSetting = false;
    let res = await $get("index/config");
    if(res.code == 1) {
      registerSetting = res.data.register_setting ? true : false
    }
    return {
      registerSetting,
    }
  },
  data() {
    return {
      telephone: '',
      smsCode: '',
      password: '',
      againPwd: '',
      isAgree: false,
      canSend: true
    }
  },
  methods: {
    async sendSMSCode() {
      if(!this.canSend) {
        return
      }
      let res = await this.$post("sms/send", {
        mobile: this.telephone,
        key: SMSType.REGISTER
      })
      if(res.code == 1) {
        this.$message({
          message: res.msg,
          type: 'success'
        });
        this.canSend = false;
      }
    },
    async registerFun() {
      if(!this.telephone) {
        this.$message({
          message: '请输入手机号',
          type: 'error'
        });
        return;
      }
      if(this.registerSetting && !this.smsCode) {
        this.$message({
          message: "请输入短信验证码",
          type: 'error'
        })
        return;
      }
      if(!this.password) {
        this.$message({
          message: '请输入密码',
          type: 'error'
        })
        return;
      }
      if(this.password != this.againPwd) {
        this.$message({
          message: '两次密码输入不一致',
          type: 'error'
        })
        return;
      }
      let res = await this.$post('account/register', {
        mobile: this.telephone, 
        password: this.password, 
        code: this.smsCode, 
        client: client
      })
      if(res.code == 1) {
        this.$message({
          message: '注册成功',
          type: 'success'
        })
        this.$router.push('/account/login')
      }
    }
  }
}
